/* eslint-disable react-hooks/exhaustive-deps */
import React, { useEffect, useState } from "react";
import * as api from '../api';

export default function ProjectDetail({ project, onBack }) {
  const [sites, setSites] = useState([]);
  const [form, setForm] = useState({ name: "", latitude: "", longitude: "", land_area_ha: "" });

  const loadSites = async () => {
    const res = await api.get(`/projects/${project.id}/sites/`);
    setSites(res.data);
  };

  useEffect(() => {
    loadSites();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const addSite = async (e) => {
    e.preventDefault();
    await api.post(`/projects/${project.id}/sites/`, {
      ...form,
      latitude: parseFloat(form.latitude),
      longitude: parseFloat(form.longitude),
      land_area_ha: form.land_area_ha ? parseFloat(form.land_area_ha) : null,
    });
    setForm({ name: "", latitude: "", longitude: "", land_area_ha: "" });
    loadSites();
  };

  const fetchEnvironmentalData = async (siteId) => {
    await api.post(`/projects/${project.id}/sites/${siteId}/environmental/fetch`);
    alert("Environmental data fetched for this site (NASA POWER).");
  };

  return (
    <div style={{ maxWidth: 800, margin: "40px auto", fontFamily: "sans-serif" }}>
      <button onClick={onBack}>← Back to Projects</button>
      <h2>{project.name}</h2>

      <h3>Sites</h3>
      <form onSubmit={addSite} style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap" }}>
        <input
          placeholder="Site name"
          value={form.name}
          onChange={(e) => setForm({ ...form, name: e.target.value })}
          required
        />
        <input
          placeholder="Latitude"
          value={form.latitude}
          onChange={(e) => setForm({ ...form, latitude: e.target.value })}
          required
        />
        <input
          placeholder="Longitude"
          value={form.longitude}
          onChange={(e) => setForm({ ...form, longitude: e.target.value })}
          required
        />
        <input
          placeholder="Land area (ha)"
          value={form.land_area_ha}
          onChange={(e) => setForm({ ...form, land_area_ha: e.target.value })}
        />
        <button type="submit">+ Add Site</button>
      </form>

      <table width="100%" cellPadding={8} style={{ borderCollapse: "collapse" }}>
        <thead>
          <tr style={{ borderBottom: "1px solid #ccc" }}>
            <th align="left">Name</th>
            <th align="left">Lat, Lon</th>
            <th align="left">Land area (ha)</th>
            <th align="left"></th>
          </tr>
        </thead>
        <tbody>
          {sites.map((s) => (
            <tr key={s.id} style={{ borderBottom: "1px solid #eee" }}>
              <td>{s.name}</td>
              <td>{s.latitude}, {s.longitude}</td>
              <td>{s.land_area_ha ?? "-"}</td>
              <td>
                <button onClick={() => fetchEnvironmentalData(s.id)}>
                  Fetch environmental data
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      {sites.length === 0 && <p>No sites yet — add one above.</p>}
    </div>
  );
}
